{"path":"notepad/storage.py","content":"import json
class Storage:
    def __init__(self, filename='notes.json'):
        self.filename = filename
        try:
            with open(self.filename, 'r') as f:
                self.notes = json.load(f)
        except FileNotFoundError:
            self.notes = []

    def save_notes(self):
        with open(self.filename, 'w') as f:
            json.dump(self.notes, f)

    def add_note(self, note):
        self.notes.append(note)
        self.save_notes()

    def get_notes(self):
        return self.notes"}

{"path":"notepad/cli.py","content":"from .storage import Storage
class NotepadCLI:
    def __init__(self):
        self.storage = Storage()

    def add(self, note):
        self.storage.add_note(note)

    def list(self):
        return self.storage.get_notes()

    def search(self, keyword):
        return [note for note in self.storage.get_notes() if keyword.lower() in note.lower()]

    def delete(self, index):
        notes = self.storage.get_notes()
        if 1 <= index <= len(notes):
            del notes[index - 1]
            self.storage.save_notes()
